body:
Bug is present on both head of main and CIRCT sifive/1/20/0.

FYI @prithayan @debs-sifive

Here's a proposed test:
```
; RUN: firtool --verilog %s | FileCheck %s

circuit Top : %[[
  {
    "class": "sifive.enterprise.grandcentral.DataTapsAnnotation",
    "keys": [
      {
        "class":"sifive.enterprise.grandcentral.DataTapModuleSignalKey",
        "module":"~Top|Foo",
        "internalPath":"random.something",
        "sink": "~Top|Top>tap"
      }
    ]
  },
  {
    "class": "firrtl.transforms.DontTouchAnnotation",
    "target": "~Top|Top>fizz"
  }
]]
  extmodule Foo :
    input in : UInt<1>
    output out : UInt<1>

  module Top:
    input in : UInt<1>
    output out : UInt<1>

    inst foo of Foo
    foo.in <= in
    out <= foo.out

    wire tap : UInt<1>

    wire fizz : UInt<1>
    fizz <= tap

; CHECK: module Top(
; CHECK-NOT: module
; CHECK:   wire fizz = foo.random.something;
; CHECK: endmodule
```

If you run this, you'll get:
```verilog
// Generated by CIRCT circtorg-0.0.0-1057-ga85125ae3
// external module Foo

module Top(
  input  in,
  output out);

  wire fizz = 1'h0;
  Foo foo (
    .in  (in),
    .out (out)
  );
endmodule
```

If you add a dont touch for `Top.tap`, you'll get:
```verilog
// Generated by CIRCT circtorg-0.0.0-1057-ga85125ae3
// external module Foo

module Top(
  input  in,
  output out);

  wire tap_internalPath = foo.random.something;
  wire tap;
  wire fizz;
  assign fizz = tap;
  assign tap = Top.tap_internalPath;
  Foo foo (
    .in  (in),
    .out (out)
  );
endmodule
```

The workaround is easy enough fortunately but the bug manifests in a pretty pernicious way.
